  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum TypeImage {\n  INITIAL\n  RESOLUTION\n  PROGRESS\n}\n\nenum Role {\n  STUDENT\n  ADMIN\n  TECHNICAL\n}\n\nenum State {\n  OPEN\n  ASSIGNED\n  IN_PROGRESS\n  VALIDATED\n  CLOSED\n}\n\nenum Priority {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum Category {\n  LIGHTING\n  URBAN_FURNITURE\n  PAVEMENT\n  CLEANING\n  GREEN_AREAS\n  SIGNAGE\n  ACCESSIBILITY\n  TECHNOLOGY\n  OTHER\n}\n\nenum IncidentEvent {\n  ASSIGN\n  START\n  REASSIGN\n  RESOLVE\n  CLOSE\n  REJECT\n}\n\nmodel User {\n  user_id   String  @id @default(uuid())\n  email     String  @unique\n  name      String\n  surname   String\n  password  String\n  nickname  String  @unique\n  role      Role\n  active    Boolean @default(true)\n  points    Int     @default(0)\n  avatarUrl String? // URL pública de la foto de perfil (Supabase Storage)\n\n  // Camps específics per a tècnics (null per a STUDENT i ADMIN).\n  // workCategory és el que utilitza l'algoritme de recomanació al panel d'admin.\n  position     String? // p. ex. \"Electricista\", \"Jardiner\"\n  workCategory Category? // àmbit principal del tècnic, lligat a Category de Report\n  company      String? // empresa contractista (Eulen, Ferrovial...)\n\n  inviteId String? @unique\n  invite   Invite? @relation(fields: [inviteId], references: [id])\n\n  reportsAssigned    Report[]            @relation(\"AssignedReports\")\n  reportsCreated     Report[]            @relation(\"CreatedReports\")\n  comments           Comment[]\n  imagesUploaded     Image[]             @relation(\"UploadedImages\")\n  pushTokens         PushToken[]\n  notifications      Notification[]\n  pointsTransactions PointsTransaction[]\n\n  createdAt    DateTime @default(now())\n  lastModified DateTime @updatedAt\n\n  @@map(\"users\")\n}\n\nmodel Report {\n  report_id   String @id @default(uuid())\n  title       String\n  description String\n\n  state    State     @default(OPEN)\n  priority Priority  @default(MEDIUM)\n  category Category?\n\n  latitude  Float\n  longitude Float\n  location  Unsupported(\"geography(Point, 4326)\")?\n\n  images            Image[]\n  comments          Comment[]\n  notifications     Notification[]\n  pointsTransaction PointsTransaction?\n\n  createdById String\n  createdBy   User   @relation(\"CreatedReports\", fields: [createdById], references: [user_id])\n\n  assignedToId String?\n  assignedTo   User?   @relation(\"AssignedReports\", fields: [assignedToId], references: [user_id])\n\n  createdAt    DateTime  @default(now())\n  lastModified DateTime  @updatedAt\n  resolvedAt   DateTime?\n\n  // Camps escrits pel sistema d'auto-classificació IA (Sprint 6).\n  // `aiSummary` és un resum d'una línia per facilitar lectura ràpida al\n  // dashboard. `aiClassifiedAt` serveix tant d'auditoria (sabem que va ser\n  // l'IA i quan) com de senyal per al frontend (no executar de nou si ja\n  // està classificat).\n  aiSummary      String?\n  aiClassifiedAt DateTime?\n\n  @@map(\"reports\")\n}\n\nmodel Comment {\n  id              String         @id @default(uuid())\n  content         String\n  transitionEvent IncidentEvent?\n\n  createdAt    DateTime @default(now())\n  lastModified DateTime @updatedAt\n\n  reportId String\n  report   Report @relation(fields: [reportId], references: [report_id])\n\n  authorId String\n  author   User   @relation(fields: [authorId], references: [user_id])\n\n  @@map(\"comments\")\n}\n\nmodel Image {\n  id   String    @id @default(uuid())\n  url  String\n  type TypeImage\n\n  createdAt    DateTime @default(now())\n  lastModified DateTime @updatedAt\n\n  reportId String\n  report   Report @relation(fields: [reportId], references: [report_id])\n\n  uploadedById String?\n  uploadedBy   User?   @relation(\"UploadedImages\", fields: [uploadedById], references: [user_id])\n\n  @@map(\"images\")\n}\n\nenum InviteStatus {\n  PENDING\n  USED\n  REVOKED\n}\n\nenum NotificationType {\n  REPORT_ASSIGNED\n  REPORT_REASSIGNED\n  REPORT_UNASSIGNED\n  REPORT_STATE_CHANGED\n  POINTS_EARNED\n}\n\n// Token de push d'un dispositiu concret. Un usuari pot tenir-ne diversos\n// (mòbil + tauleta). Quan Expo ens diu que un token està mort (DeviceNotRegistered)\n// el marquem com a inactiu en lloc d'esborrar-lo, per tenir traça històrica.\nmodel PushToken {\n  id       String  @id @default(uuid())\n  token    String  @unique\n  platform String // 'ios' | 'android'\n  active   Boolean @default(true)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [user_id], onDelete: Cascade)\n\n  createdAt  DateTime @default(now())\n  lastSeenAt DateTime @default(now())\n\n  @@index([userId, active])\n  @@map(\"push_tokens\")\n}\n\n// Notificació persistida al sistema (campana / badge / historial in-app).\n// El push és efímer: si el dispositiu està apagat es perd. Aquesta taula és\n// la \"veritat\" del que ha passat i el que el client mòbil ha de mostrar.\nmodel Notification {\n  id    String           @id @default(uuid())\n  type  NotificationType\n  title String\n  body  String\n  read  Boolean          @default(false)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [user_id], onDelete: Cascade)\n\n  reportId String?\n  report   Report? @relation(fields: [reportId], references: [report_id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n\n  @@index([userId, read, createdAt])\n  @@map(\"notifications\")\n}\n\nmodel Invite {\n  id        String       @id @default(uuid())\n  email     String       @unique\n  role      Role\n  token     String       @unique\n  status    InviteStatus @default(PENDING)\n  expiresAt DateTime     @default(dbgenerated(\"(now() + interval '7 days')\"))\n  createdAt DateTime     @default(now())\n\n  user User?\n\n  @@map(\"invites\")\n}\n\n// Historial atòmic de cada premi de punts (Sprint Gamificació).\n// Cada fila representa una concessió única vinculada a un report. La unicitat\n// per reportId garanteix que mai es premiï dos cops el mateix report, encara\n// que la transició CLOSE es disparés repetidament per un bug futur.\n// El camp `priority` és un snapshot del moment de l'award, perquè si l'admin\n// canvia la prioritat després el premi reflecteix el valor real aplicat.\nmodel PointsTransaction {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [user_id], onDelete: Cascade)\n\n  reportId String @unique\n  report   Report @relation(fields: [reportId], references: [report_id], onDelete: Cascade)\n\n  amount   Int\n  priority Priority\n\n  createdAt DateTime @default(now())\n\n  @@index([userId, createdAt])\n  @@map(\"points_transactions\")\n}\n",
